package orchestration

import (
	"github.com/kastheco/kasmos/config/taskparser"
)

// WaveState represents the current state of wave orchestration for a plan.
type WaveState int

const (
	WaveStateIdle         WaveState = iota // Not started
	WaveStateRunning                       // Current wave's tasks are running
	WaveStateWaveComplete                  // Current wave finished, awaiting user confirmation
	WaveStateAllComplete                   // All waves finished
)

// taskStatus tracks the completion state of a single task.
type taskStatus int

const (
	taskPending taskStatus = iota
	taskRunning
	taskComplete
	taskFailed
)

// WaveOrchestrator manages wave-based parallel task execution for a single plan.
type WaveOrchestrator struct {
	taskFile          string
	plan              *taskparser.Plan
	state             WaveState
	currentWave       int                // 0-indexed into plan.Waves
	taskStates        map[int]taskStatus // task number → status
	waitingForConfirm bool               // true once we've shown the wave-complete dialog
}

// NewWaveOrchestrator creates an orchestrator for the given plan.
func NewWaveOrchestrator(planFile string, plan *taskparser.Plan) *WaveOrchestrator {
	return &WaveOrchestrator{
		taskFile:   planFile,
		plan:       plan,
		state:      WaveStateIdle,
		taskStates: make(map[int]taskStatus),
	}
}

// State returns the current orchestration state.
func (o *WaveOrchestrator) State() WaveState {
	return o.state
}

// TaskFile returns the plan filename this orchestrator manages.
func (o *WaveOrchestrator) TaskFile() string {
	return o.taskFile
}

// TotalWaves returns the number of waves in the plan.
func (o *WaveOrchestrator) TotalWaves() int {
	return len(o.plan.Waves)
}

// TotalTasks returns the total number of tasks across all waves.
func (o *WaveOrchestrator) TotalTasks() int {
	total := 0
	for _, w := range o.plan.Waves {
		total += len(w.Tasks)
	}
	return total
}

// CurrentWaveNumber returns the 1-indexed wave number currently active.
func (o *WaveOrchestrator) CurrentWaveNumber() int {
	if o.currentWave >= len(o.plan.Waves) {
		return 0
	}
	return o.plan.Waves[o.currentWave].Number
}

// CurrentWaveTasks returns the tasks in the current wave.
func (o *WaveOrchestrator) CurrentWaveTasks() []taskparser.Task {
	if o.currentWave >= len(o.plan.Waves) {
		return nil
	}
	return o.plan.Waves[o.currentWave].Tasks
}

// StartNextWave advances to the next wave and returns its tasks.
// Returns nil if all waves are complete.
func (o *WaveOrchestrator) StartNextWave() []taskparser.Task {
	if o.state == WaveStateAllComplete {
		return nil
	}
	if o.state == WaveStateWaveComplete {
		o.currentWave++
		o.waitingForConfirm = false // reset for next wave
	}
	if o.currentWave >= len(o.plan.Waves) {
		o.state = WaveStateAllComplete
		return nil
	}

	o.state = WaveStateRunning
	tasks := o.plan.Waves[o.currentWave].Tasks
	for _, t := range tasks {
		o.taskStates[t.Number] = taskRunning
	}
	return tasks
}

// MarkTaskComplete marks a task as successfully completed.
// If all tasks in the current wave are done, transitions state.
// Idempotent: calling again on an already-resolved task is a no-op.
func (o *WaveOrchestrator) MarkTaskComplete(taskNumber int) {
	if o.taskStates[taskNumber] != taskRunning {
		return
	}
	o.taskStates[taskNumber] = taskComplete
	o.checkWaveComplete()
}

// MarkTaskFailed marks a task as failed.
// Other tasks in the wave continue. Wave completes when all tasks resolve.
// Idempotent: calling again on an already-resolved task is a no-op.
func (o *WaveOrchestrator) MarkTaskFailed(taskNumber int) {
	if o.taskStates[taskNumber] != taskRunning {
		return
	}
	o.taskStates[taskNumber] = taskFailed
	o.checkWaveComplete()
}

// NeedsConfirm returns true if the wave just completed and the user hasn't
// been shown the confirmation dialog yet. Calling this marks the dialog as shown.
func (o *WaveOrchestrator) NeedsConfirm() bool {
	if o.state == WaveStateWaveComplete && !o.waitingForConfirm {
		o.waitingForConfirm = true
		return true
	}
	return false
}

// ResetConfirm resets the one-shot confirm latch so NeedsConfirm() can return true
// again on the next check. Call this when the user cancels a wave-advance confirmation
// so the prompt re-appears on the subsequent metadata tick (fixes deadlock).
func (o *WaveOrchestrator) ResetConfirm() {
	o.waitingForConfirm = false
}

// RetryFailedTasks transitions all failed tasks in the current wave back to running
// and sets the orchestrator state to WaveStateRunning. Returns the tasks that were
// retried (previously failed). Returns nil if there are no failed tasks to retry.
func (o *WaveOrchestrator) RetryFailedTasks() []taskparser.Task {
	if o.currentWave >= len(o.plan.Waves) {
		return nil
	}
	var tasks []taskparser.Task
	for _, t := range o.plan.Waves[o.currentWave].Tasks {
		if o.taskStates[t.Number] == taskFailed {
			o.taskStates[t.Number] = taskRunning
			tasks = append(tasks, t)
		}
	}
	if len(tasks) > 0 {
		o.state = WaveStateRunning
		o.waitingForConfirm = false
	}
	return tasks
}

// IsCurrentWaveComplete returns true if all tasks in the current wave have resolved.
func (o *WaveOrchestrator) IsCurrentWaveComplete() bool {
	return o.state == WaveStateWaveComplete || o.state == WaveStateAllComplete
}

// CompletedTaskCount returns the number of completed tasks in the current wave.
func (o *WaveOrchestrator) CompletedTaskCount() int {
	return o.countCurrentWaveByStatus(taskComplete)
}

// FailedTaskCount returns the number of failed tasks in the current wave.
func (o *WaveOrchestrator) FailedTaskCount() int {
	return o.countCurrentWaveByStatus(taskFailed)
}

// IsTaskRunning returns true if the given task number is currently in the running state.
// Used to gate the "Mark complete" context menu action.
func (o *WaveOrchestrator) IsTaskRunning(taskNumber int) bool {
	return o.taskStates[taskNumber] == taskRunning
}

// IsTaskComplete returns true if the given task number has completed successfully.
func (o *WaveOrchestrator) IsTaskComplete(taskNumber int) bool {
	return o.taskStates[taskNumber] == taskComplete
}

// IsTaskFailed returns true if the given task number has failed.
func (o *WaveOrchestrator) IsTaskFailed(taskNumber int) bool {
	return o.taskStates[taskNumber] == taskFailed
}

// HeaderContext returns the plan header for inclusion in task prompts.
func (o *WaveOrchestrator) HeaderContext() string {
	return o.plan.HeaderContext()
}

// ShouldPostWaveCompleteComment returns true when an intermediate wave_complete
// comment should be posted. Single-wave plans return false — they use the
// "all waves complete" event instead. Nil-receiver safe.
func (o *WaveOrchestrator) ShouldPostWaveCompleteComment() bool {
	return o != nil && o.TotalWaves() > 1
}

// RestoreToWave fast-forwards the orchestrator wave-by-wave to targetWave,
// auto-completing all tasks in earlier waves, then marks the specified task
// numbers as complete in the target wave. Remaining tasks in the target wave
// are left in the running state.
func (o *WaveOrchestrator) RestoreToWave(targetWave int, completedTasks []int) {
	completedSet := make(map[int]bool, len(completedTasks))
	for _, n := range completedTasks {
		completedSet[n] = true
	}

	for o.currentWave < len(o.plan.Waves) {
		o.StartNextWave()
		if o.CurrentWaveNumber() == targetWave {
			break
		}
		// Mark all tasks in this earlier wave as complete to advance.
		for _, t := range o.plan.Waves[o.currentWave].Tasks {
			o.MarkTaskComplete(t.Number)
		}
	}

	// Apply the actual task states for the target wave.
	for _, t := range o.plan.Waves[o.currentWave].Tasks {
		if completedSet[t.Number] {
			o.MarkTaskComplete(t.Number)
		}
		// Running tasks stay in taskRunning.
	}
}

// BuildTaskPrompt is a convenience wrapper that builds the task prompt for a
// task in the current wave.
func (o *WaveOrchestrator) BuildTaskPrompt(task taskparser.Task, peerCount int) string {
	return BuildTaskPrompt(o.plan, task, o.CurrentWaveNumber(), o.TotalWaves(), peerCount)
}

func (o *WaveOrchestrator) checkWaveComplete() {
	if o.currentWave >= len(o.plan.Waves) {
		return
	}
	tasks := o.plan.Waves[o.currentWave].Tasks
	for _, t := range tasks {
		s := o.taskStates[t.Number]
		if s == taskRunning || s == taskPending {
			return // still in progress
		}
	}
	// All tasks resolved — check if more waves remain
	if o.currentWave+1 >= len(o.plan.Waves) {
		o.state = WaveStateAllComplete
	} else {
		o.state = WaveStateWaveComplete
	}
}

func (o *WaveOrchestrator) countCurrentWaveByStatus(s taskStatus) int {
	if o.currentWave >= len(o.plan.Waves) {
		return 0
	}
	count := 0
	for _, t := range o.plan.Waves[o.currentWave].Tasks {
		if o.taskStates[t.Number] == s {
			count++
		}
	}
	return count
}

package orchestration

import (
	"testing"

	"github.com/kastheco/kasmos/config/taskparser"
	"github.com/stretchr/testify/assert"
	"github.com/stretchr/testify/require"
)

func TestNewWaveOrchestrator(t *testing.T) {
	plan := &taskparser.Plan{
		Goal: "test",
		Waves: []taskparser.Wave{
			{Number: 1, Tasks: []taskparser.Task{
				{Number: 1, Title: "First", Body: "do first"},
				{Number: 2, Title: "Second", Body: "do second"},
			}},
			{Number: 2, Tasks: []taskparser.Task{
				{Number: 3, Title: "Third", Body: "do third"},
			}},
		},
	}

	orch := NewWaveOrchestrator("plan.md", plan)
	assert.Equal(t, WaveStateIdle, orch.State())
	assert.Equal(t, 2, orch.TotalWaves())
	assert.Equal(t, 3, orch.TotalTasks())
}

func TestWaveOrchestrator_StartWave(t *testing.T) {
	plan := &taskparser.Plan{
		Waves: []taskparser.Wave{
			{Number: 1, Tasks: []taskparser.Task{
				{Number: 1, Title: "First", Body: "do first"},
			}},
		},
	}

	orch := NewWaveOrchestrator("plan.md", plan)
	tasks := orch.StartNextWave()

	assert.Equal(t, WaveStateRunning, orch.State())
	assert.Equal(t, 1, orch.CurrentWaveNumber())
	require.Len(t, tasks, 1)
	assert.Equal(t, "First", tasks[0].Title)
}

func TestWaveOrchestrator_TaskCompleted(t *testing.T) {
	plan := &taskparser.Plan{
		Waves: []taskparser.Wave{
			{Number: 1, Tasks: []taskparser.Task{
				{Number: 1, Title: "First", Body: "do first"},
				{Number: 2, Title: "Second", Body: "do second"},
			}},
		},
	}

	orch := NewWaveOrchestrator("plan.md", plan)
	orch.StartNextWave()

	assert.False(t, orch.IsCurrentWaveComplete())

	orch.MarkTaskComplete(1)
	assert.False(t, orch.IsCurrentWaveComplete())

	orch.MarkTaskComplete(2)
	assert.True(t, orch.IsCurrentWaveComplete())
	assert.Equal(t, WaveStateAllComplete, orch.State())
}

func TestWaveOrchestrator_TaskFailed(t *testing.T) {
	plan := &taskparser.Plan{
		Waves: []taskparser.Wave{
			{Number: 1, Tasks: []taskparser.Task{
				{Number: 1, Title: "First", Body: "do first"},
				{Number: 2, Title: "Second", Body: "do second"},
			}},
		},
	}

	orch := NewWaveOrchestrator("plan.md", plan)
	orch.StartNextWave()

	orch.MarkTaskFailed(1)
	orch.MarkTaskComplete(2)

	assert.Equal(t, WaveStateAllComplete, orch.State())
	assert.Equal(t, 1, orch.FailedTaskCount())
	assert.Equal(t, 1, orch.CompletedTaskCount())
}

func TestWaveOrchestrator_MultiWaveProgression(t *testing.T) {
	plan := &taskparser.Plan{
		Waves: []taskparser.Wave{
			{Number: 1, Tasks: []taskparser.Task{
				{Number: 1, Title: "First", Body: "do first"},
			}},
			{Number: 2, Tasks: []taskparser.Task{
				{Number: 2, Title: "Second", Body: "do second"},
			}},
		},
	}

	orch := NewWaveOrchestrator("plan.md", plan)

	// Wave 1
	orch.StartNextWave()
	orch.MarkTaskComplete(1)
	assert.Equal(t, WaveStateWaveComplete, orch.State())

	// Advance to wave 2
	tasks := orch.StartNextWave()
	assert.Equal(t, WaveStateRunning, orch.State())
	assert.Equal(t, 2, orch.CurrentWaveNumber())
	require.Len(t, tasks, 1)

	// Complete wave 2
	orch.MarkTaskComplete(2)
	assert.Equal(t, WaveStateAllComplete, orch.State())
}

func TestWaveOrchestrator_AllComplete(t *testing.T) {
	plan := &taskparser.Plan{
		Waves: []taskparser.Wave{
			{Number: 1, Tasks: []taskparser.Task{
				{Number: 1, Title: "Only", Body: "do it"},
			}},
		},
	}

	orch := NewWaveOrchestrator("plan.md", plan)
	orch.StartNextWave()
	orch.MarkTaskComplete(1)

	// No more waves — should be AllComplete
	assert.Equal(t, WaveStateAllComplete, orch.State())
}

func TestWaveOrchestrator_ResetConfirmAllowsReprompt(t *testing.T) {
	plan := &taskparser.Plan{
		Waves: []taskparser.Wave{
			{Number: 1, Tasks: []taskparser.Task{
				{Number: 1, Title: "First", Body: "do first"},
			}},
			{Number: 2, Tasks: []taskparser.Task{
				{Number: 2, Title: "Second", Body: "do second"},
			}},
		},
	}

	orch := NewWaveOrchestrator("plan.md", plan)
	orch.StartNextWave()
	orch.MarkTaskComplete(1) // wave 1 complete

	// First call consumes the one-shot latch
	assert.True(t, orch.NeedsConfirm(), "first call must return true")
	assert.False(t, orch.NeedsConfirm(), "second call must return false (latch consumed)")

	// After reset, NeedsConfirm should fire again
	orch.ResetConfirm()
	assert.True(t, orch.NeedsConfirm(), "after ResetConfirm, must return true again")
}

func TestIsTaskRunning(t *testing.T) {
	plan := &taskparser.Plan{
		Waves: []taskparser.Wave{
			{Number: 1, Tasks: []taskparser.Task{{Number: 1}, {Number: 2}}},
		},
	}
	orch := NewWaveOrchestrator("test.md", plan)
	orch.StartNextWave()

	assert.True(t, orch.IsTaskRunning(1), "task 1 should be running after StartNextWave")
	assert.True(t, orch.IsTaskRunning(2), "task 2 should be running after StartNextWave")

	orch.MarkTaskComplete(1)
	assert.False(t, orch.IsTaskRunning(1), "task 1 should not be running after MarkTaskComplete")
	assert.True(t, orch.IsTaskRunning(2), "task 2 should still be running")

	assert.False(t, orch.IsTaskRunning(99), "unknown task should return false")
}

func TestWaveOrchestrator_TaskStatusQueries(t *testing.T) {
	plan := &taskparser.Plan{
		Waves: []taskparser.Wave{
			{Number: 1, Tasks: []taskparser.Task{
				{Number: 1, Title: "Task 1"},
				{Number: 2, Title: "Task 2"},
				{Number: 3, Title: "Task 3"},
			}},
		},
	}
	orch := NewWaveOrchestrator("test.md", plan)
	orch.StartNextWave()

	// All should be running initially.
	assert.True(t, orch.IsTaskRunning(1))
	assert.False(t, orch.IsTaskComplete(1))
	assert.False(t, orch.IsTaskFailed(1))

	orch.MarkTaskComplete(1)
	assert.True(t, orch.IsTaskComplete(1))
	assert.False(t, orch.IsTaskRunning(1))

	orch.MarkTaskFailed(2)
	assert.True(t, orch.IsTaskFailed(2))
	assert.False(t, orch.IsTaskRunning(2))

	// Task 3 still running.
	assert.True(t, orch.IsTaskRunning(3))
}

func TestWaveOrchestrator_RetryFailedTasksRestoresRunning(t *testing.T) {
	plan := &taskparser.Plan{
		Waves: []taskparser.Wave{
			{Number: 1, Tasks: []taskparser.Task{
				{Number: 1, Title: "First", Body: "do first"},
				{Number: 2, Title: "Second", Body: "do second"},
			}},
			{Number: 2, Tasks: []taskparser.Task{
				{Number: 3, Title: "Third", Body: "do third"},
			}},
		},
	}

	orch := NewWaveOrchestrator("plan.md", plan)
	orch.StartNextWave()

	// T1 fails, T2 completes — wave done with failure
	orch.MarkTaskFailed(1)
	orch.MarkTaskComplete(2)
	require.Equal(t, WaveStateWaveComplete, orch.State(), "wave must be WaveComplete with failure")
	assert.Equal(t, 1, orch.FailedTaskCount())

	// Retry the failed task
	retried := orch.RetryFailedTasks()

	assert.Equal(t, WaveStateRunning, orch.State(), "state must be Running after retry")
	require.Len(t, retried, 1, "must return only the failed task")
	assert.Equal(t, 1, retried[0].Number, "retried task must be T1")

	// After the retried task completes, wave is done again (with more waves pending)
	orch.MarkTaskComplete(1)
	assert.Equal(t, WaveStateWaveComplete, orch.State(), "wave must be WaveComplete after retry+complete")
	assert.Equal(t, 0, orch.FailedTaskCount(), "no more failures after retry completes")
}

func TestRestoreToWave(t *testing.T) {
	plan := &taskparser.Plan{
		Waves: []taskparser.Wave{
			{Number: 1, Tasks: []taskparser.Task{{Number: 1}, {Number: 2}}},
			{Number: 2, Tasks: []taskparser.Task{{Number: 3}}},
		},
	}
	orch := NewWaveOrchestrator("plan.md", plan)
	orch.RestoreToWave(2, []int{3})
	assert.Equal(t, WaveStateAllComplete, orch.State())
	assert.Equal(t, 2, orch.CurrentWaveNumber())
}

func TestRestoreToWave_PartialCompletion(t *testing.T) {
	plan := &taskparser.Plan{
		Waves: []taskparser.Wave{
			{Number: 1, Tasks: []taskparser.Task{{Number: 1}}},
			{Number: 2, Tasks: []taskparser.Task{{Number: 2}, {Number: 3}}},
		},
	}
	orch := NewWaveOrchestrator("plan.md", plan)
	orch.RestoreToWave(2, []int{2}) // task 3 still running
	assert.Equal(t, WaveStateRunning, orch.State())
	assert.True(t, orch.IsTaskComplete(2))
	assert.True(t, orch.IsTaskRunning(3))
}

func TestShouldPostWaveCompleteComment(t *testing.T) {
	single := &taskparser.Plan{Waves: []taskparser.Wave{
		{Number: 1, Tasks: []taskparser.Task{{Number: 1}}},
	}}
	multi := &taskparser.Plan{Waves: []taskparser.Wave{
		{Number: 1, Tasks: []taskparser.Task{{Number: 1}}},
		{Number: 2, Tasks: []taskparser.Task{{Number: 2}}},
	}}
	assert.False(t, NewWaveOrchestrator("s.md", single).ShouldPostWaveCompleteComment())
	assert.True(t, NewWaveOrchestrator("m.md", multi).ShouldPostWaveCompleteComment())

	// nil receiver safety
	var nilOrch *WaveOrchestrator
	assert.False(t, nilOrch.ShouldPostWaveCompleteComment())
}

func TestBuildTaskPrompt_Method(t *testing.T) {
	plan := &taskparser.Plan{
		Goal: "Test goal",
		Waves: []taskparser.Wave{
			{Number: 1, Tasks: []taskparser.Task{
				{Number: 1, Title: "First", Body: "do first"},
				{Number: 2, Title: "Second", Body: "do second"},
			}},
		},
	}
	orch := NewWaveOrchestrator("plan.md", plan)
	orch.StartNextWave()
	prompt := orch.BuildTaskPrompt(plan.Waves[0].Tasks[0], 2)
	assert.Contains(t, prompt, "Task 1")
	assert.Contains(t, prompt, "Test goal")
	assert.Contains(t, prompt, "Wave 1 of 1")
	assert.Contains(t, prompt, "parallel") // peerCount > 1
}

package orchestration

import (
	"fmt"
	"strings"

	"github.com/kastheco/kasmos/config/taskparser"
)

// BuildTaskPrompt constructs the prompt for a single task instance.
func BuildTaskPrompt(plan *taskparser.Plan, task taskparser.Task, waveNumber, totalWaves, peerCount int) string {
	var sb strings.Builder

	sb.WriteString(fmt.Sprintf("Implement Task %d: %s\n\n", task.Number, task.Title))
	sb.WriteString("Load the `kasmos-coder` skill before starting. Also load `cli-tools` for the tool selection reference.\n\n")

	// Plan context
	header := plan.HeaderContext()
	if header != "" {
		sb.WriteString("## Plan Context\n\n")
		sb.WriteString(header)
		sb.WriteString("\n")
	}

	// Wave context
	sb.WriteString(fmt.Sprintf("## Wave %d of %d\n\n", waveNumber, totalWaves))

	// Parallel awareness — only for multi-task waves
	if peerCount > 1 {
		sb.WriteString(fmt.Sprintf("## Parallel Execution\n\n"))
		sb.WriteString(fmt.Sprintf("You are Task %d of %d in Wave %d. %d other agents are working in parallel on this same worktree.\n\n",
			task.Number, peerCount, waveNumber, peerCount-1))

		sb.WriteString("Your assigned files are listed in the Task Instructions below. Prioritize those files. ")
		sb.WriteString("If you must touch a shared file (go.mod, go.sum, imports), make minimal surgical changes - ")
		sb.WriteString("do not reorganize, reformat, or refactor anything outside your task scope.\n\n")

		sb.WriteString("CRITICAL - shared worktree rules:\n")
		sb.WriteString("- NEVER run `git add .` or `git add -A` - you will commit other agents' in-progress work\n")
		sb.WriteString("- NEVER run `git stash` or `git reset` - you will destroy sibling agents' changes\n")
		sb.WriteString("- NEVER run `git checkout -- <file>` on files you didn't modify - you will revert a sibling's edits\n")
		sb.WriteString("- NEVER run formatters/linters across the whole project (e.g. `go fmt ./...`) - scope them to your files only\n")
		sb.WriteString("- NEVER try to fix test failures in files outside your task - they may be caused by incomplete parallel work\n")
		sb.WriteString("- DO `git add` only the specific files you changed\n")
		sb.WriteString("- DO commit frequently with your task number in the message\n")
		sb.WriteString("- DO expect untracked files and uncommitted changes that are not yours - ignore them\n\n")
	}

	// Task body
	sb.WriteString("## Task Instructions\n\n")
	sb.WriteString(task.Body)
	sb.WriteString("\n")

	return sb.String()
}

// BuildWaveAnnotationPrompt returns the prompt used when a planner is respawned
// to add ## Wave headers to an existing plan that is missing them.
// It instructs the planner to annotate the plan, commit the change, and write
// the sentinel signal so kasmos can resume the implementation flow.
func BuildWaveAnnotationPrompt(planFile string) string {
	return fmt.Sprintf(
		"The plan at docs/plans/%[1]s is missing ## Wave N headers required for kasmos wave orchestration. "+
			"Please annotate the plan by wrapping all tasks under ## Wave N sections. "+
			"Every plan needs at least ## Wave 1 — even single-task trivial plans. "+
			"Keep all existing task content intact; only add the ## Wave headers.\n\n"+
			"After annotating:\n"+
			"1. Commit: git add docs/plans/%[1]s && git commit -m \"plan: add wave headers to %[1]s\"\n"+
			"2. Signal completion: touch .kasmos/signals/planner-finished-%[1]s\n"+
			"Do not edit plan-state.json directly.",
		planFile,
	)
}

package orchestration

import (
	"testing"

	"github.com/kastheco/kasmos/config/taskparser"
	"github.com/stretchr/testify/assert"
)

func TestBuildTaskPrompt(t *testing.T) {
	plan := &taskparser.Plan{
		Goal:         "Build a feature",
		Architecture: "Modular approach",
		TechStack:    "Go, bubbletea",
	}
	task := taskparser.Task{
		Number: 2,
		Title:  "Update Tests",
		Body:   "**Step 1:** Write the test\n\n**Step 2:** Run it",
	}

	prompt := BuildTaskPrompt(plan, task, 1, 3, 4)

	// Plan context
	assert.Contains(t, prompt, "Build a feature")
	assert.Contains(t, prompt, "Modular approach")
	assert.Contains(t, prompt, "Go, bubbletea")
	assert.Contains(t, prompt, "cli-tools")

	// Task identity
	assert.Contains(t, prompt, "Task 2")
	assert.Contains(t, prompt, "Update Tests")
	assert.Contains(t, prompt, "Write the test")
	assert.Contains(t, prompt, "Wave 1 of 3")

	// Parallel awareness (multi-task)
	assert.Contains(t, prompt, "Task 2 of 4")
