	orch.MarkTaskComplete(1)
	assert.Equal(t, WaveStateWaveComplete, orch.State(), "wave must be WaveComplete after retry+complete")
	assert.Equal(t, 0, orch.FailedTaskCount(), "no more failures after retry completes")
}

